using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = "api/shipments";
        var parameters = new List<string>();
        if (!string.IsNullOrEmpty(statusFilter))
            parameters.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrEmpty(searchTerm))
            parameters.Add($"search={Uri.EscapeDataString(searchTerm)}");
        if (parameters.Count > 0)
            query += "?" + string.Join("&", parameters);

        return await _http.GetFromJsonAsync<List<Shipment>>(query) ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = newStatus });
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}

