using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation using in-memory seed data.
/// Replace with EF Core or another data store for production.
/// </summary>
public class ShipmentServerService : IShipmentService
{
    private static readonly List<Shipment> _shipments = GenerateSeedData();

    private static List<Shipment> GenerateSeedData() =>
    [
        new() { Id = 1, TrackingNumber = "SHP-20260501-001", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, EstimatedDelivery = new DateTime(2026, 6, 2), Description = "Electronics — 3 pallets", CreatedAt = new DateTime(2026, 5, 1) },
        new() { Id = 2, TrackingNumber = "SHP-20260503-002", Origin = "Chicago, IL", Destination = "Miami, FL", Status = ShipmentStatus.OutForDelivery, EstimatedDelivery = new DateTime(2026, 5, 28), Description = "Medical supplies", CreatedAt = new DateTime(2026, 5, 3) },
        new() { Id = 3, TrackingNumber = "SHP-20260505-003", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.Pending, EstimatedDelivery = new DateTime(2026, 6, 5), Description = "Furniture — fragile", CreatedAt = new DateTime(2026, 5, 5) },
        new() { Id = 4, TrackingNumber = "SHP-20260507-004", Origin = "Houston, TX", Destination = "Boston, MA", Status = ShipmentStatus.Delivered, EstimatedDelivery = new DateTime(2026, 5, 20), Description = "Auto parts", CreatedAt = new DateTime(2026, 5, 7) },
        new() { Id = 5, TrackingNumber = "SHP-20260510-005", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, EstimatedDelivery = new DateTime(2026, 6, 8), Description = "Perishable goods — refrigerated", CreatedAt = new DateTime(2026, 5, 10) },
        new() { Id = 6, TrackingNumber = "SHP-20260512-006", Origin = "Atlanta, GA", Destination = "Dallas, TX", Status = ShipmentStatus.PickedUp, EstimatedDelivery = new DateTime(2026, 6, 1), Description = "Retail merchandise", CreatedAt = new DateTime(2026, 5, 12) },
        new() { Id = 7, TrackingNumber = "SHP-20260515-007", Origin = "Portland, OR", Destination = "Nashville, TN", Status = ShipmentStatus.InTransit, EstimatedDelivery = new DateTime(2026, 6, 3), Description = "Construction materials", CreatedAt = new DateTime(2026, 5, 15) },
        new() { Id = 8, TrackingNumber = "SHP-20260518-008", Origin = "Detroit, MI", Destination = "Charlotte, NC", Status = ShipmentStatus.Pending, EstimatedDelivery = new DateTime(2026, 6, 10), Description = "Office equipment", CreatedAt = new DateTime(2026, 5, 18) },
    ];

    public Task<List<Shipment>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = _shipments.AsEnumerable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
            query = query.Where(s => s.Status == status);

        if (!string.IsNullOrEmpty(searchTerm))
            query = query.Where(s =>
                s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                s.Origin.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                s.Description.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

        return Task.FromResult(query.OrderByDescending(s => s.CreatedAt).ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id)
            ?? throw new KeyNotFoundException($"Shipment {id} not found.");
        shipment.Status = newStatus;
        return Task.FromResult(shipment);
    }
}

