else if (shipments.Count == 0)
{
    <div class="alert alert-info">No shipments match your filter.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover align-middle">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Description</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.Description</td>
                        <td>
                            @if (shipment.Status != ShipmentTracker.Client.Models.ShipmentStatus.Delivered)
                            {
                                <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                        value="@shipment.Status"
                                        @onchange="e => UpdateStatusAsync(shipment, e)">
                                    @foreach (var s in Enum.GetValues<ShipmentTracker.Client.Models.ShipmentStatus>())
                                    {
                                        <option value="@s" selected="@(s == shipment.Status)">@s</option>
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentTracker.Client.Models.Shipment>? shipments;
    private string searchTerm = string.Empty;
    private string statusFilter = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipmentsAsync();
    }

    private async Task LoadShipmentsAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync(
            string.IsNullOrEmpty(statusFilter) ? null : statusFilter,
            string.IsNullOrEmpty(searchTerm) ? null : searchTerm);
    }

    private async Task UpdateStatusAsync(ShipmentTracker.Client.Models.Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentTracker.Client.Models.ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            await LoadShipmentsAsync();
        }
    }

    private static string GetStatusBadge(ShipmentTracker.Client.Models.ShipmentStatus status) => status switch
    {
        ShipmentTracker.Client.Models.ShipmentStatus.Pending => "bg-secondary",
        ShipmentTracker.Client.Models.ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentTracker.Client.Models.ShipmentStatus.InTransit => "bg-primary",
        ShipmentTracker.Client.Models.ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentTracker.Client.Models.ShipmentStatus.Delivered => "bg-success",
        ShipmentTracker.Client.Models.ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ShipmentTracker.Client.Services.IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>📋 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260501-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-success" @onclick="SearchAsync" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h4 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h4>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6 class="text-muted">Origin</h6>
                    <p class="fs-5">@shipment.Origin</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Destination</h6>
                    <p class="fs-5">@shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Description</h6>
                    <p>@shipment.Description</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Estimated Delivery</h6>
                    <p class="fs-5">
                        @if (shipment.EstimatedDelivery.HasValue)
                        {
                            @shipment.EstimatedDelivery.Value.ToString("dddd, MMMM dd, yyyy")
                        }
                        else
                        {
                            <span class="text-muted">TBD</span>
                        }
                    </p>
                </div>
                <div class="col-12">
                    <h6 class="text-muted">Shipment Created</h6>
                    <p>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                </div>
            </div>

            <hr />
            <h5>Delivery Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentTracker.Client.Models.Shipment? shipment;
    private bool searched;
    private bool isSearching;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchAsync();
    }

    private async Task SearchAsync()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        isSearching = false;
    }

    private static string GetStatusBadge(ShipmentTracker.Client.Models.ShipmentStatus status) => status switch
    {
        ShipmentTracker.Client.Models.ShipmentStatus.Pending => "bg-secondary",
        ShipmentTracker.Client.Models.ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentTracker.Client.Models.ShipmentStatus.InTransit => "bg-primary",
        ShipmentTracker.Client.Models.ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentTracker.Client.Models.ShipmentStatus.Delivered => "bg-success",
        ShipmentTracker.Client.Models.ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentTracker.Client.Models.ShipmentStatus status) => status switch
    {
        ShipmentTracker.Client.Models.ShipmentStatus.Delayed => "bg-danger",
        ShipmentTracker.Client.Models.ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentTracker.Client.Models.ShipmentStatus status) => status switch
    {
        ShipmentTracker.Client.Models.ShipmentStatus.Pending => 10,
        ShipmentTracker.Client.Models.ShipmentStatus.PickedUp => 30,
        ShipmentTracker.Client.Models.ShipmentStatus.InTransit => 55,
        ShipmentTracker.Client.Models.ShipmentStatus.OutForDelivery => 80,
        ShipmentTracker.Client.Models.ShipmentStatus.Delivered => 100,
        ShipmentTracker.Client.Models.ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

